const token = flow.get("eztvToken");
const baseUrl = flow.get("eztvBaseUrl") || "https://10.187.138.16";
const endpointId = msg.endpointId || msg.payload;

if (!token) {
    msg.payload = "No EZTV token. Run login first.";
    return [null, msg];
}

if (!endpointId) {
    msg.payload = "No endpointId supplied";
    return [null, msg];
}

msg.method = "GET";
msg.url = `${baseUrl}/eztv/api/endpoints/${endpointId}`;

msg.headers = {
    "Authorization": `Bearer ${token}`,
    "Accept": "application/json"
};

msg.payload = null;

return [msg, null];

let ep = msg.payload;

if (typeof ep === "string") {
    ep = JSON.parse(ep);
}

const mv = Array.isArray(ep.multiViewChannels) ? ep.multiViewChannels : [];

let layout = "1";
let windows = ["-1", "-1", "-1", "-1"];

if (mv.length > 0) {
    layout = String(mv.length);

    for (let i = 0; i < Math.min(mv.length, 4); i++) {
        windows[i] = String(mv[i].number ?? "-1");
    }
}

msg.payload = {
    endpointId: ep.id,
    endpointName: ep.name,
    endpointLabel: ep.description || ep.name,
    layout,
    windows,
    rawMultiViewChannels: mv,
    rawEndpoint: ep
};

return msg;

msg.headers = {
    "Content-Type": "application/json",
    "Accept": "application/json"
};

msg.payload = JSON.stringify({
    username: "admin@dss-internal",
    password: "1qaz!QAZ",
    customerPlatform: "STB"
});

return msg;

try {
    let body = msg.payload;

    if (typeof body === "string") {
        body = JSON.parse(body);
    }

    const token = body.tokenFixedLength || body.token || body.accessToken;

    if (!token) {
        msg.success = false;
        msg.payload = "No token found in login response";
        return msg;
    }

    flow.set("eztvToken", token);

    msg.success = true;
    msg.payload = "EZTV token stored";
    return msg;

} catch (err) {
    msg.success = false;
    msg.payload = `Login failed: ${err.message}`;
    return msg;
}

const token = flow.get("eztvToken");
const baseUrl = flow.get("eztvBaseUrl") || "https://10.187.138.16";

const endpointId = msg.endpointId;
const layout = String(msg.layout || "1");
const windows = Array.isArray(msg.windows)
    ? msg.windows.map(v => String(v || "-1"))
    : ["-1", "-1", "-1", "-1"];

while (windows.length < 4) {
    windows.push("-1");
}

if (!token) {
    msg.success = false;
    msg.payload = "No EZTV token. Run login first.";
    return msg;
}

if (!endpointId) {
    msg.success = false;
    msg.payload = "No endpointId supplied.";
    return msg;
}

msg.method = "POST";
msg.url = `${baseUrl}/eztv/api/events/immediate/activities`;

msg.headers = {
    "Authorization": `Bearer ${token}`,
    "Content-Type": "application/json",
    "Accept": "application/json"
};

msg.payload = JSON.stringify({
    action: "LoadChannelMultiview",
    actionCluster: "DSS",
    actionParameters: [
        { name: "Slots", value: layout },
        { name: "ChannelOverlayInfo", value: "false" },
        { name: "Channel1_ID", value: windows[0] },
        { name: "Channel2_ID", value: windows[1] },
        { name: "Channel3_ID", value: windows[2] },
        { name: "Channel4_ID", value: windows[3] }
    ],
    actionTargets: [
        {
            id: endpointId,
            cmdTargetType: "Endpoint"
        }
    ]
};

return msg;

let body = msg.payload;

try {
    if (typeof body === "string") {
        body = JSON.parse(body);
    }

    msg.success = true;
    msg.activityId = body.activityId;
    msg.applyState = body.state;
    msg.payload = body;

    return msg;

} catch (err) {
    msg.success = false;
    msg.payload = {
        error: "Could not parse EZTV apply response",
        details: err.message,
        raw: msg.payload
    };
    return msg;
}

const slot = Number(msg.payload);

const walls = flow.get("walls") || {};
const wallId = flow.get("selectedWallId") || "";
const wall = walls[wallId];

if (!wall || !slot) {
    msg.payload = "No wall/display selected";
    return [msg, null, null, null, null, null, null];
}

const display = wall.displays.find(d => Number(d.slot) === slot);

if (!display) {
    msg.payload = `Slot ${slot} not found`;
    return [msg, null, null, null, null, null, null];
}

const layout = String(display.layout || "1");
const windows = display.windows || ["-1", "-1", "-1", "-1"];

flow.set("selectedSlot", slot);
flow.set("editLayout", layout);
flow.set("editWindow1", String(windows[0] || "-1"));
flow.set("editWindow2", String(windows[1] || "-1"));
flow.set("editWindow3", String(windows[2] || "-1"));
flow.set("editWindow4", String(windows[3] || "-1"));

return [
    { payload: `Editing ${wall.wallName} - Slot ${slot}` },
    { payload: layout },
    { payload: String(windows[0] || "-1") },
    { payload: String(windows[1] || "-1") },
    { payload: String(windows[2] || "-1") },
    { payload: String(windows[3] || "-1") },
    { payload: "refresh" }
];

const rows = Array.isArray(msg.payload) ? msg.payload : [msg.payload];

