const presetName = (flow.get("presetNameInput") || "").trim();
if (!presetName) {
    msg.payload = "Enter a preset name";
    return msg;
}

const wallState = flow.get("wallState") || {};
const presets = flow.get("presets") || {};

// deep copy current wall
presets[presetName] = JSON.parse(JSON.stringify(wallState));

flow.set("presets", presets);
flow.set("selectedPreset", presetName);

msg.payload = `Saved preset: ${presetName}`;
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [msg.payload];

const endpointDetailsById = {};

const options = rows
    .filter(r => r["Id"] && (r["Description"] || r["Name"]))
    .map(r => {
        const id = String(r["Id"]).trim();
        const name = String(r["Name"] || "").trim();
        const description = String(r["Description"] || "").trim();
        const location = String(r["Location"] || "").trim();

        const operatorLabel = description || name;

        endpointDetailsById[id] = {
            id,
            name,
            description,
            operatorLabel,
            location,
            ipAddress: String(r["IP Address"] || r["IPAddress"] || "").trim()
        };

        return {
            label: operatorLabel,
            value: id
        };
    })
    .sort((a, b) => a.label.localeCompare(b.label));

options.unshift({
    label: "Unassigned",
    value: ""
});

flow.set("endpointOptions", options);
flow.set("endpointDetailsById", endpointDetailsById);

msg.ui_update = { options };
return msg;

let walls = flow.get("walls") || {};

let configWallId = flow.get("configWallId") || "";
const wallName = (flow.get("editWallName") || "").trim();
const displayCount = Number(flow.get("editWallDisplayCount") || 0);

if (!wallName || displayCount < 1) {
    msg.payload = "Wall name and display count are required";
    return msg;
}

function makeWallId(name) {
    return name
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, "-")
        .replace(/^-|-$/g, "");
}

function makeDisplay(slot) {
    return {
        slot,
        label: `Display ${slot}`,
        endpointId: "",
        endpointLabel: "Unassigned",
        endpointName: "",
        endpointDescription: "",
        endpointLocation: "",
        layout: "1",
        windows: ["-1", "-1", "-1", "-1"]
    };
}

let wall;

// update existing config wall
if (configWallId && walls[configWallId]) {
    wall = walls[configWallId];
    wall.wallName = wallName;

    const oldCount = wall.displays.length;

    if (displayCount > oldCount) {
        for (let i = oldCount + 1; i <= displayCount; i++) {
            wall.displays.push(makeDisplay(i));
        }
    } else if (displayCount < oldCount) {
        wall.displays = wall.displays.slice(0, displayCount);
    }

    wall.displayCount = displayCount;

    msg.payload = `Saved wall: ${wall.wallName}`;
}

// create new config wall
else {
    const wallId = makeWallId(wallName);

    if (walls[wallId]) {
        msg.payload = "A wall with that name already exists";
        return msg;
    }

    const displays = [];

    for (let i = 1; i <= displayCount; i++) {
        displays.push(makeDisplay(i));
    }

    wall = {
        wallId,
        wallName,
        displayCount,
        displays
    };

    walls[wallId] = wall;
    configWallId = wallId;
    flow.set("configWallId", wallId);

    msg.payload = `Added wall: ${wall.wallName}`;
}

flow.set("walls", walls);

// useful for downstream nodes
msg.wallId = configWallId;
msg.wall = wall;

return msg;

const walls = flow.get("walls") || {};

const configWallId = flow.get("configWallId") || "";
let selectedWallId = flow.get("selectedWallId") || "";

const options = Object.values(walls)
    .sort((a, b) => a.wallName.localeCompare(b.wallName))
    .map(wall => ({
        label: wall.wallName,
        value: wall.wallId
    }));

const validIds = new Set(options.map(o => o.value));

if (selectedWallId && !validIds.has(selectedWallId)) {
    selectedWallId = "";
    flow.set("selectedWallId", "");
    flow.set("selectedSlot", "");
}

const safeOptions = options.length
    ? options
    : [{ label: "No walls configured", value: "" }];

return [
    {
        ui_update: { options: safeOptions },
        payload: validIds.has(configWallId) ? configWallId : ""
    },
    {
        ui_update: { options: safeOptions },
        payload: validIds.has(selectedWallId) ? selectedWallId : ""
    }
];

const wallId = flow.get("configWallId");
let walls = flow.get("walls") || {};

if (!wallId || !walls[wallId]) {
    msg.payload = "No config wall selected";
    return msg;
}

const deletedName = walls[wallId].wallName;

delete walls[wallId];

flow.set("walls", walls);

// Clear Config selection if needed
if (flow.get("configWallId") === wallId) {
