// Clear Overview selection if needed
if (flow.get("selectedWallId") === wallId) {
    flow.set("selectedWallId", "");
    flow.set("selectedSlot", "");
    flow.set("selectedEndpointId", "");
}

msg.payload = `Deleted wall: ${deletedName}`;

return msg;

