    flow.set("configEndpointId", "");

    return [
        { payload: "" },
        { payload: 1 },
        { payload: "No config wall selected" },
        { payload: "" }
    ];
}

flow.set("configWallId", wallId);
flow.set("editWallName", wall.wallName);
flow.set("editWallDisplayCount", wall.displayCount);

const firstDisplay = wall.displays?.[0];
const firstSlot = firstDisplay ? String(firstDisplay.slot) : "";

flow.set("configSlot", firstSlot);
flow.set("configEndpointId", firstDisplay?.endpointId || "");

return [
    { payload: wall.wallName },
    { payload: wall.displayCount },
    { payload: `Configuring wall: ${wall.wallName}` },
    { payload: firstSlot }
];

flow.set("configWallId", "");
flow.set("editWallName", "");
flow.set("editWallDisplayCount", 1);
flow.set("configSlot", "");
flow.set("configEndpointId", "");

return [
    { payload: "" },
    { payload: 1 },
    { payload: "New wall: enter a name and display count, then click Save Wall" },
    { payload: "" }
];

// initialize wall registry if missing
let walls = flow.get("walls");

if (!walls) {
    walls = {};
    flow.set("walls", walls);
}

// selected wall
if (flow.get("selectedWallId") === undefined) {
    flow.set("selectedWallId", "");
}

// wall edit form defaults
if (flow.get("editWallName") === undefined) {
    flow.set("editWallName", "");
}

if (flow.get("editWallDisplayCount") === undefined) {
    flow.set("editWallDisplayCount", 6);
}

// optional future structures
if (!flow.get("endpointOptions")) {
    flow.set("endpointOptions", []);
}

if (!flow.get("endpointDetailsById")) {
    flow.set("endpointDetailsById", {});
}

if (!flow.get("channelOptions")) {
    flow.set("channelOptions", []);
}

if (!flow.get("channelLabelMap")) {
    flow.set("channelLabelMap", {});
}

if (!flow.get("wallPresets")) {
    flow.set("wallPresets", {});
}

if (!flow.get("controlMode")) {
    flow.set("controlMode", "development");
}

msg.payload = "Wall controller initialized";

return msg;

const walls = flow.get("walls") || {};
const configWallId = flow.get("configWallId") || "";
const wall = walls[configWallId];

if (!wall || !Array.isArray(wall.displays) || wall.displays.length === 0) {
    msg.ui_update = {
        options: [{ label: "No displays configured", value: "" }]
    };
    msg.payload = "";
    return msg;
}

const options = wall.displays.map(d => ({
    label: `${wall.wallName} - ${d.label}`,
    value: String(d.slot)
}));

let configSlot = String(flow.get("configSlot") || "");

if (!options.some(o => o.value === configSlot)) {
    configSlot = options[0]?.value || "";
    flow.set("configSlot", configSlot);
}

msg.ui_update = { options };
msg.payload = configSlot;

return msg;

const slot = Number(msg.payload);
const walls = flow.get("walls") || {};
const configWallId = flow.get("configWallId") || "";
const wall = walls[configWallId];

if (!wall || !slot) {
    flow.set("configSlot", "");
    flow.set("configEndpointId", "");

    return [
        { payload: "" },
        { payload: "No display selected" }
    ];
}

const display = wall.displays.find(d => d.slot === slot);

if (!display) {
    return [
        { payload: "" },
        { payload: `Display ${slot} not found` }
    ];
}

flow.set("configSlot", slot);
flow.set("configEndpointId", display.endpointId || "");

return [
    { payload: display.endpointId || "" },
    { payload: `Editing ${display.label || `Display ${slot}`}` }
];

const wallId = flow.get("configWallId");
const slot = Number(flow.get("configSlot"));
const selectedEndpointId = flow.get("configEndpointId") || "";

let walls = flow.get("walls") || {};
const endpointDetailsById = flow.get("endpointDetailsById") || {};

const wall = walls[wallId];

if (!wall) {
    msg.payload = "No wall selected";
    return msg;
}

const display = wall.displays.find(d => d.slot === slot);

if (!display) {
    msg.payload = "No display selected";
    return msg;
}

if (!selectedEndpointId) {
    display.endpointId = "";
    display.endpointLabel = "Unassigned";
    display.endpointName = "";
    display.endpointDescription = "";
    display.endpointLocation = "";
} else {
    const ep = endpointDetailsById[selectedEndpointId];

    if (!ep) {
        msg.payload = "Selected endpoint not found";
        return msg;
    }

    display.endpointId = ep.id;
    display.endpointLabel = ep.operatorLabel;
    display.endpointName = ep.name;
    display.endpointDescription = ep.description;
    display.endpointLocation = ep.location;
}

flow.set("walls", walls);

msg.payload = `Assigned ${display.endpointLabel} to ${wall.wallName} ${display.label}`;
return msg;

const wallId = msg.payload || "";
const walls = flow.get("walls") || {};
const wall = walls[wallId];

if (!wall) {

    flow.set("selectedWallId", "");
    flow.set("selectedSlot", "");

    return [
        { payload: "" },
        { payload: "No wall selected" }
    ];
}

flow.set("selectedWallId", wallId);

const firstDisplay = wall.displays?.[0];
const firstSlot = firstDisplay
    ? String(firstDisplay.slot)
    : "";

flow.set("selectedSlot", firstSlot);

return [
    { payload: firstSlot },
    { payload: `Selected wall: ${wall.wallName}` }
];

const mode = msg.payload || "development";

flow.set("controlMode", mode);

msg.payload = `Mode set to ${mode}`;

return msg;

const mode = flow.get("controlMode") || "development";

msg.payload = {
    mode
};

return msg;

msg.payload = JSON.stringify({
    version: 1,
    exportedAt: new Date().toISOString(),
    walls: flow.get("walls") || {}
}, null, 2);

msg.filename = "wall-config.json";
return msg;

const mode = flow.get("controlMode") || "development";

if (mode === "online") {
    return [null, msg];
}

return [msg, null];
